import java.util.Arrays;

public static long solve(long[] piles) {
    Arrays.sort(piles);
    long sum = 0;
    int n = piles.length;
    int k = n / 3;
    for (int i = n - 2; i >= k; i -= 2) {
        sum += piles[i];
    }
    return sum;
}
